window.GIoTapiBaseUrl = "https://api.giot.ir";
window.GIoTapiBasePort = 443;
window.GIoWSBaseUrl = "https://mqttws.giot.ir";
window.GIoWSBasePort = 443;

async function postData(data, resource_path) {
    return $.ajax({
        url: window.GIoTapiBaseUrl + resource_path,
        type: 'POST',
        headers: {
			'Content-Type': 'application/json; charset=UTF-8',
            'Accept': 'application/json',
			'X-Requested-With': 'XMLHttpRequest'
        },
        dataType: 'json',    // نوع پاسخ مورد انتظار
        data: JSON.stringify(data) // داده‌ها به صورت رشته JSON
    }).then(response => {
        // در صورت موفقیت
        return response;
    }).catch(xhr => {
        // در صورت خطا
        console.log("AJAX Error - Status:", xhr.status, xhr.statusText);
        console.log("Response Text:", xhr.responseText);
        // جزئیات بیشتر برای خطایابی
        console.error("Full XHR object:", xhr);
        throw xhr; // خطا را مجدداً پرتاب کن
    });
}

async function getData(resourcePath) {
    // Return the Deferred's promise to the caller
    return $.ajax({
        url: window.GIoTapiBaseUrl + resourcePath, // URL to send the request to
        type: 'GET',
		headers: {
			'Content-Type': 'application/json; charset=UTF-8',
            'Accept': 'application/json',
			'X-Requested-With': 'XMLHttpRequest'
        },
        dataType: 'json'
    }).then(response => {
        return response;
    }).catch(xhr => {
        // On error, return the error message as a string
        var errorMessage = xhr.status + ': ' + xhr.statusText;
        console.log("Error - " + errorMessage);
        return errorMessage;
    });
}